#!/usr/bin/env node
/**
 * Deterministic Janus TestSpec -> generator TestPlan compiler.
 *
 * Usage:
 *   node tests/e2e/generator/compile-testspec-to-testplan.mjs \
 *     --spec documentation/TEST_SPEC/05_ux_behavior/01_capability_overview_and_help.md
 *
 * Output:
 * - Writes documentation/test-runs/<next_test_run_id>_plan.json
 * - Validates with validate-test-plan.mjs
 * - Validates runner generation with generate-live-runner.mjs
 * - Prints the deterministic TEST SKILL 2 handover generated by
 *   create-test-skill2-handover.mjs
 */

import fs from 'node:fs';
import path from 'node:path';
import { spawnSync } from 'node:child_process';

function parseArgs(argv) {
  const args = {};
  for (let i = 2; i < argv.length; i += 2) {
    if (argv[i] === '--spec') args.spec = argv[i + 1];
  }
  return args;
}

function fail(message, detail = '') {
  console.error(`TEST PLAN BLOCKED\n\nIssue:\n- ${message}`);
  if (detail) console.error(`\nDetail:\n${detail}`);
  process.exit(1);
}

function runNode(args) {
  const result = spawnSync(process.execPath, args, { encoding: 'utf-8' });
  return {
    ok: result.status === 0,
    output: `${result.stdout || ''}${result.stderr || ''}`.trim(),
  };
}

function nextRunId(date = new Date()) {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  const prefix = `TEST-RUN-${y}-${m}-${d}-`;
  for (let i = 1; i <= 999; i += 1) {
    const id = `${prefix}${String(i).padStart(3, '0')}`;
    const planPath = `documentation/test-runs/${id}_plan.json`;
    if (!fs.existsSync(planPath)) return { id, planPath };
  }
  fail(`No free TestRun sequence left for ${prefix}`);
}

function section(md, heading) {
  const escaped = heading.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const re = new RegExp(`^## ${escaped}\\s*$([\\s\\S]*?)(?=^##\\s|(?![\\s\\S]))`, 'm');
  const match = md.match(re);
  return match ? match[1].trim() : '';
}

function parseTable(block) {
  const lines = block
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter((line) => line.startsWith('|') && line.endsWith('|'));
  if (lines.length < 2) return [];
  const headers = lines[0].split('|').slice(1, -1).map((h) => h.trim());
  return lines.slice(2).map((line) => {
    const cells = line.split('|').slice(1, -1).map((c) => c.trim());
    return Object.fromEntries(headers.map((h, i) => [h, cells[i] || '']));
  });
}

function firstBulletValue(md, label) {
  const re = new RegExp(`- ${label}:\\s*(.+)`);
  return md.match(re)?.[1]?.trim() || '';
}

function firstStrategyValue(md, label) {
  const re = new RegExp(`- ${label}:\\s*(.+)`, 'i');
  return md.match(re)?.[1]?.trim() || '';
}

function modelForProvider(provider) {
  if (provider === 'Gemini') return 'gemini-3-flash-preview';
  return 'gpt-5.4-nano';
}

function providerSuffix(provider) {
  return provider === 'Gemini' ? 'GEMINI' : 'GPT';
}

function normalizeText(value) {
  return String(value || '').toLowerCase();
}

function testMutatesOrSharesState(testCase) {
  const text = normalizeText(`${testCase.id} ${testCase.name} ${testCase.type} ${testCase.prompt}`);
  return /loesch|lösch|delete|remove|verschieb|move|rename|umbenenn|speicher|save|erstelle|create|ordner|datei|filesystem|workspace|kalender|calendar|termin|event|memory|gedächtnis|gedaechtnis|merke|remember|kontakt|email|mail/.test(text);
}

function classifyParallelSafety(testCase, specParallelFit) {
  if (testCase.provider === 'Any') {
    return {
      parallelSafe: true,
      isolationKey: 'static',
      testDataNamespace: 'static',
      parallelReason: 'Provider-free/static test case',
    };
  }

  const mutatesOrSharesState = testMutatesOrSharesState(testCase);
  const highFit = /high/i.test(specParallelFit);
  const mediumFit = /medium/i.test(specParallelFit);
  const readOnlyProviderCase = !mutatesOrSharesState && !['security', 'prompt_injection', 'manual_gate'].includes(testCase.type);
  const parallelSafe = readOnlyProviderCase && (highFit || mediumFit || !specParallelFit);

  return {
    parallelSafe,
    isolationKey: parallelSafe ? `${testCase.provider}:readonly` : `${testCase.provider}:serial`,
    testDataNamespace: parallelSafe ? `${testCase.provider.toLowerCase()}-readonly-${testCase.id}` : `serial-${testCase.id}`,
    parallelReason: parallelSafe ? 'Read-only provider-isolated case' : 'Serial due to mutation/shared-state/safety risk',
  };
}

function buildParallelizationPolicy(md, tests) {
  const specParallelFit = firstStrategyValue(md, 'Parallelization Fit');
  const forceSerialForToolEvidence = /Tool Execution Contract and Evidence/i.test(md);
  const forceSerialForLoggingPrivacy = /Logging, Telemetry and Audit Privacy/i.test(md);
  for (const testCase of tests) {
    Object.assign(
      testCase,
      forceSerialForToolEvidence || forceSerialForLoggingPrivacy
        ? {
            parallelSafe: false,
            isolationKey: `${testCase.provider}:serial`,
            testDataNamespace: `serial-${testCase.id}`,
            parallelReason: forceSerialForLoggingPrivacy
              ? 'Serial for shared log and telemetry evidence stability'
              : 'Serial for tool-evidence contract stability',
          }
        : classifyParallelSafety(testCase, specParallelFit),
    );
  }

  const parallelSafeCount = tests.filter((testCase) => testCase.parallelSafe).length;
  const serialCount = tests.length - parallelSafeCount;
  const recommendedWorkers = parallelSafeCount === 0 ? 1 : serialCount === 0 ? 3 : 2;

  return {
    schema: 'janus-testplan.parallelization.v1',
    enabled: parallelSafeCount > 0,
    recommendedWorkers,
    defaultWorkers: 1,
    mode: serialCount === 0 ? 'all_parallel_safe' : parallelSafeCount > 0 ? 'mixed_parallel_and_serial' : 'serial_only',
    parallelSafeTests: parallelSafeCount,
    serialTests: serialCount,
    isolation: {
      chat: 'new_chat_per_test',
      browserContext: 'playwright_worker_context',
      provider: 'per_test_header_model_selection',
      testDataNamespace: 'per_test_field',
    },
    notes: [
      'Use recommendedWorkers only when Janus backend and provider quotas are stable.',
      'Mutation, memory, calendar and filesystem stateful tests remain serial by default.',
      'Provider-parallel tests must use separate chats and testDataNamespace values.',
    ],
  };
}

