function addProviderTests(tests, rows, type, idKey, nameKey, promptKey, criterionKey, patternKey, providers, specPath = '') {
  for (const row of rows) {
    const baseId = row[idKey];
    const prompt = row[promptKey];
    if (!baseId || !prompt) continue;
    const specPatterns = patternKey && row[patternKey] ? row[patternKey] : null;
    for (const provider of providers) {
      tests.push({
        id: `${baseId}-${providerSuffix(provider)}`,
        name: row[nameKey] || row.ExpectedIntent || row.Risk || row['Injection Surface'] || baseId,
        type,
        provider,
        model: modelForProvider(provider),
        prompt,
        expected: expectedFor(baseId, prompt, row[criterionKey] || '', specPath, specPatterns),
      });
    }
  }
}

function addBrowserSecurityTests(tests, rows, type, idKey, nameKey, promptKey, criterionKey) {
  for (const row of rows) {
    const id = row[idKey];
    const prompt = row[promptKey];
    if (!id || !prompt) continue;
    tests.push({
      id,
      name: row[nameKey] || id,
      type,
      provider: 'Any',
      model: 'deterministic-http',
      prompt,
      expected: {
        containsAny: ['PASS'],
        mustNotContain: ['FAIL'],
        criterion: row[criterionKey] || '',
      },
    });
  }
}

function compile(specPath) {
  if (!/^documentation\/TEST_SPEC\/(?:[^\\/]+\/)*[^\\/]+\.md$/.test(specPath)) {
    fail(`TestSpec path must be documentation/TEST_SPEC/<category>/<slug>.md or documentation/TEST_SPEC/<slug>.md. Received: ${specPath}`);
  }
  if (!fs.existsSync(specPath)) fail(`TestSpec not found: ${specPath}`);

  const md = fs.readFileSync(specPath, 'utf-8');
  const title = firstBulletValue(md, 'Capability Name') || firstBulletValue(md, 'TestSpec Name') || 'Janus TestPlan';
  const providers = ['GPT', 'Gemini'];
  const { id: testRunId, planPath } = nextRunId();

  const functional = parseTable(section(md, 'FUNCTIONAL TEST MATRIX'));
  const intents = parseTable(section(md, 'NATURAL LANGUAGE INTENT MATRIX'));
  const security = parseTable(section(md, 'SECURITY TEST CASES'));
  const injections = parseTable(section(md, 'PROMPT INJECTION TEST CASES'));
  const live = parseTable(section(md, 'LIVE JANUS TEST CASES'));

  const tests = [];
  const isBrowserSecuritySpec = /04_security_headers_cookies_and_browser_surface/i.test(specPath);

  if (isBrowserSecuritySpec) {
    addBrowserSecurityTests(tests, functional, 'functional', 'TestCase-ID', 'Scenario', 'Test Method', 'Acceptance Criterion');
    addBrowserSecurityTests(tests, security, 'security', 'SecurityCase-ID', 'Risk', 'Test Method', 'Acceptance Criterion');
  } else {
    addProviderTests(tests, functional, 'functional', 'TestCase-ID', 'Scenario', 'User Prompt / Action', 'Acceptance Criterion', null, providers, specPath);
    addProviderTests(tests, intents, 'intent_routing', 'Intent-ID', 'Expected Intent', 'User Phrase', 'Acceptance Criterion', 'Expected containsAny Patterns', providers, specPath);

    for (const row of security) {
      const baseId = row['SecurityCase-ID'];
      const prompt = row['Test Method'] || row.Risk;
      if (!baseId || !prompt) continue;
      const specPatterns = row['Expected containsAny Patterns'] || null;
      for (const provider of providers) {
        tests.push({
          id: `${baseId}-${providerSuffix(provider)}`,
          name: row.Risk || baseId,
          type: 'security',
          provider,
          model: modelForProvider(provider),
          prompt,
          expected: expectedFor(baseId, prompt, row['Acceptance Criterion'] || '', specPath, specPatterns),
        });
      }
    }

    for (const row of injections) {
      const baseId = row['InjectionCase-ID'];
      const prompt = row['Malicious Input/Data'];
      if (!baseId || !prompt) continue;
      for (const provider of providers) {
        tests.push({
          id: `${baseId}-${providerSuffix(provider)}`,
          name: `Prompt injection ${baseId}`,
          type: 'prompt_injection',
          provider,
          model: modelForProvider(provider),
          prompt,
          expected: expectedFor(baseId, prompt, row['Acceptance Criterion'] || '', specPath, null),
        });
      }
    }

    for (const row of live) {
      const liveId = row['LiveCase-ID'];
      const provider = row.Provider === 'Gemini' ? 'Gemini' : 'GPT';
      const prompt = /same prompt/i.test(row.Steps || '') ? 'Was kannst du?' : 'Was kannst du?';
      if (!liveId) continue;
      tests.push({
        id: liveId,
        name: row['Expected Result'] || `Live Janus ${liveId}`,
        type: 'functional',
        provider,
        model: modelForProvider(provider),
        prompt,
        expected: expectedFor(liveId, prompt, row['Expected Result'] || '', specPath, null),
      });
    }
  }

  if (tests.length === 0) fail('No executable tests could be derived from TestSpec tables.');
  const parallelization = buildParallelizationPolicy(md, tests);

  const plan = {
    testRunId,
    title,
    executionMode: 'LIVE_VISUAL',
    target: isBrowserSecuritySpec ? 'JANUS_BROWSER_SECURITY' : 'JANUS_CHAT',
    chatWindow: 'A',
    baseUrl: 'http://localhost:5173/',
    backendHealthUrl: 'http://localhost:8001/api/health',
    timeouts: {
      testCaseMs: 300000,
      assistantResponseMs: 60000,
      streamRequestMs: 60000,
    },
    strategies: {
      send: 'chat_button_click_send_v1',
      wait: 'assistant_stream_complete_v1',
      evidence: 'capture_network_v1',
      evaluate: 'contains_any_v1',
    },
    parallelization,
    tests,
  };

  fs.mkdirSync(path.dirname(planPath), { recursive: true });
  fs.writeFileSync(planPath, `${JSON.stringify(plan, null, 2)}\n`, 'utf-8');

  const validator = runNode(['tests/e2e/generator/validate-test-plan.mjs', '--plan', planPath]);
  if (!validator.ok) fail(`Strict validator failed for ${planPath}.`, validator.output);

  const runnerPath = planPath.replace(/_plan\.json$/, '_generated.spec.js');
  const generator = runNode(['tests/e2e/generator/generate-live-runner.mjs', '--plan', planPath, '--out', runnerPath]);
  if (!generator.ok) fail(`Runner generation failed for ${planPath}.`, generator.output);

  const handover = runNode(['tests/e2e/generator/create-test-skill2-handover.mjs', '--plan', planPath, '--spec', specPath]);
  if (!handover.ok) fail(`Handover generation failed for ${planPath}.`, handover.output);
  const handoverPath = planPath.replace(/_plan\.json$/, '_skill2_handover.txt');
  fs.writeFileSync(handoverPath, `${handover.output}\n`, 'utf-8');

  console.log('TEST PLAN CREATED');
  console.log(`TestRun ID: ${testRunId}`);
  console.log(`TestPlan Path: ${planPath}`);
  console.log(`Skill2 Handover Path: ${handoverPath}`);
  console.log(`Input TestSpec Path: ${specPath}`);
  console.log('');
  console.log(validator.output);
  console.log(generator.output);
  console.log('');
  console.log('COPY HANDOVER FOR TEST SKILL 2 (copy the gray box exactly)');
  console.log(handover.output);
}

const args = parseArgs(process.argv);
if (!args.spec) fail('Usage: node tests/e2e/generator/compile-testspec-to-testplan.mjs --spec documentation/TEST_SPEC/<category>/<slug>.md');
compile(args.spec);
